/**
 * OFAC SDN screening gate (31 CFR §501.404).
 *
 * Scenario #11 of guides/use-cases.md: a transaction whose creditor
 * side has a sanctions screening with screening_score >= 95
 * (effective exact match against the OFAC SDN List) is blocked and
 * an OFAC blocked-property report is due within 10 days (§501.603).
 *
 * Reads `creditor_payment_account.compliance_screenings[]`. If any
 * sanctions-type screening on the creditor side carries a non-zero
 * match_count, emits a blocked Control per creditor-side LedgerAccount.
 * The cap=0 + is_blocked=true combination converts to status='rejected'
 * with rejected_rule='ofac_sdn_match' at limits-at-entry time.
 *
 * The corpus exercises the high-confidence band only — graduated
 * bands (#11a-d) are a future extension.
 */
export const handler = async (input) => {
  const creditor = input.creditor_payment_account;
  if (!creditor) return { ledger_accounts: {} };

  const screenings = creditor.compliance_screenings || [];
  const hit = screenings.some(function (s) {
    return s.screening_type === 'sanctions' && (s.match_count || 0) > 0;
  });
  if (!hit) return { ledger_accounts: {} };

  const las = creditor.las || [];
  const ledger_accounts = {};
  for (const la of las) {
    ledger_accounts[la.id] = {
      daily_debit_cap: 0,
      daily_credit_cap: 0,
      reason: 'ofac_sdn_match',
      block_reason: 'ofac_sdn_match',
      is_blocked: true
    };
  }
  return { ledger_accounts };
};
